class Solution {
    public List<Integer> sequentialDigits(int low, int high) {
        List<Integer> result = new ArrayList<>();
        for (int digits = String.valueOf(low).length(); digits <= String.valueOf(high).length(); digits++) {
            for (int start = 1; start <= 9 - digits + 1; start++) {
                int num = 0;
                for (int i = 0; i < digits; i++) {
                    num = num * 10 + start + i;
                }
                if (num >= low && num <= high) {
                    result.add(num);
                }
            }
        }
        return result;
    }
}
